function LoginForm() {
  const [email, setEmail] = React.useState('');
  const [submitted, setSubmitted] = React.useState(false);

  function handleSubmit(e) {
    // BUG: the page reloads because the default form action is never prevented
    setSubmitted(true);
  }

  return (
    <div style={{ maxWidth: '400px', margin: '40px auto', padding: '32px', background: '#16213e', borderRadius: '8px', fontFamily: 'sans-serif' }}>
      <h2 style={{ color: '#e0e0e0', marginTop: 0 }}>Login</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="email"
          value={email}
          onChange={setEmail}
          placeholder="Enter your email"
          style={{ width: '100%', padding: '10px', background: '#0f3460', border: '1px solid #533483', borderRadius: '4px', color: '#e0e0e0', boxSizing: 'border-box', marginBottom: '16px' }}
        />
        <button type="submit" style={{ width: '100%', padding: '10px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '1rem' }}>Sign In</button>
      </form>
      {submitted && (
        <p data-testid="success" style={{ color: '#4caf50', marginTop: '16px' }}>Logged in as: {email}</p>
      )}
    </div>
  );
}
